      if (path === "/config") {
        if (request.method === "PUT") {
          await kv.put(CFG_KEY, await request.text());
          return json({ ok: true }, 200, origin);
        }
        if (request.method === "GET") {
          const v = await kv.get(CFG_KEY);
          return json(v ?? "{}", 200, origin);
        }
      }

